"""
MKT Original Commentary — 2 Samuel chapters 22–23
Run: python3 scripts/zc-original-2samuel-22-23.py

Ch 22 = Psalm 18 (with minor MT variants); the song of deliverance.
Ch 23 = David's last oracle + the thirty mighty men list.

Translation decisions noted throughout:
- Two Hebrew words for 'rock': sela (cleft rock, refuge) vs. tsur (bedrock, firmness)
- The 'horn of salvation' (qeren yisʿî) — horn as power/honor symbol
- 'Sheol cords' vs. 'death cords' — two parallel images in v5-6
- v36 ʿanwātəḵā: 'condescension / humility / gentleness' — disputed rendering
- v51 ḥesed: 'steadfast love' — the covenantal faithfulness term
- Ch 23 v1 huqqam ʿal: 'raised on high / raised to prominence' — messianic resonance
- Ch 23 v3 môšēl bāʾādām: 'one who rules over men' — the just ruler ideal
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "22": {
    "1": "<p><strong>Superscription and textual relationship to Psalm 18.</strong> This chapter is almost identical to Psalm 18, with approximately 30 minor variants between the two MT versions (differences in prepositions, conjunctions, and a few substantive word choices). The superscription here is prose: 'David spoke to the LORD the words of this song on the day the LORD delivered him from the hand of all his enemies and from the hand of Saul.' The double specification — all enemies and Saul specifically — signals that Saul represents the paradigmatic threat from which YHWH delivered the anointed. The superscription's placement at the end of the Samuel narrative gives the poem a retrospective, summarizing function: the whole of David's life is framed by deliverance. The double <em>YHWH</em> in the superscription emphasizes that both the deliverance and the song belong to covenant relationship.</p>",
    "2": "<p><strong>Three opening divine epithets.</strong> 'The LORD is my rock (<em>salʿî</em>), my fortress (<em>mĕṣûdātî</em>), and my deliverer (<em>mĕpalṭî</em>).' The word for rock here is <em>sela</em> (cleft rock, crevice), referring to a cave or rocky outcrop used as a refuge — concrete imagery drawn from David's fugitive years in the Judean wilderness (cf. 1 Sam 23:28, Sela Hammahlekoth, 'rock of parting'). <em>Mĕṣûdāh</em> is a stronghold or fortress, again concrete wilderness/military imagery. <em>Pālat</em> (to deliver, cause to escape) is the MKT's 'deliverer' — an active rescue vocabulary rather than a static epithet. The three epithets build a portrait of YHWH as the one who provides refuge, security, and active rescue.</p>",
    "3": "<p><strong>Second cluster of divine epithets, with the second rock-word.</strong> 'The God of my rock (<em>ʾĕlōhê ṣûrî</em>) — in him I take refuge.' Here the rock shifts to <em>tsur</em> (bedrock, foundational stone), the other major Hebrew rock-word. <em>Sela</em> emphasizes the crevice/hiding place; <em>tsur</em> emphasizes the solid, immovable foundation. The phrase 'horn of my salvation' (<em>qeren yisʿî</em>) uses the horn as the OT symbol of strength and honor (Ps 75:4-5; 89:17, 24). 'My stronghold' (<em>miśgabbî</em>), 'my refuge' (<em>minoūsî</em>), and 'my savior' (<em>mōšiʿî</em>) complete the series. The accumulation of seven epithets in vv2-3 is a rhetorical climax expressing that YHWH exhausts the vocabulary of protection.</p>",
    "4": "<p><strong>The praise-and-salvation formula.</strong> '<em>Mĕhullāl</em> (worthy of praise, praise-worthy) I will call on the LORD' — <em>hālal</em> in the Pual participle: YHWH is the one who is perpetually praised, the fitting object of all praise. 'And I am saved (<em>wĕmiʾōyĕbay iwwāšēaʿ</em>) from my enemies' — the salvation following the call on YHWH is stated as a standing truth, not a future hope. The structure of v4 is the compressed narrative of David's entire life: call on YHWH → be saved from enemies.</p>",
    "5": "<p><strong>The death-waves strophe.</strong> 'The waves of death (<em>misbrê māwet</em>) engulfed me; the torrents of Belial (<em>naḥălê bəliyyaʿal</em>) terrified me.' The word <em>miṣbâ</em> (from <em>sbb</em>, to surround) designates the crashing waves that surround a swimmer; it also appears in Ps 18:4. 'Torrents of Belial' — <em>bəliyyaʿal</em> (worthlessness, destruction) appears here as a personified force of destruction, as in Job 18:13 ('firstborn of death'). In later literature <em>Belial</em> becomes a demonic proper name (2 Cor 6:15: 'What accord has Christ with Belial?'). The verse describes not merely military danger but the ontological threat of annihilation.</p>",
    "6": "<p><strong>Sheol-cords and death-snares.</strong> 'The cords of Sheol (<em>ḥeblê šĕʾôl</em>) wrapped around me; the snares of death (<em>môqĕšê māwet</em>) set themselves before me.' <em>Ḥebel</em> can mean both 'cord/rope' and 'pang/sorrow' — the deliberate ambiguity is maintained in translation. <em>Šĕʾôl</em> is the Hebrew underworld, the place of the dead, the realm of shadows (<em>rəpāʾîm</em>). 'Snares of death' (<em>môqĕšîm</em>) uses the hunting-trap imagery: the psalmist is the prey and death is the trapper. The poetic intensity of vv5-6 — four images of mortal threat — mirrors the rhetorical convention of covenant-lawsuit prayers that describe maximum distress before appealing to the divine judge.</p>",
    "7": "<p><strong>The cry heard from the temple.</strong> 'In my distress (<em>baṣṣar</em>) I called to YHWH... from his temple (<em>hêḵālô</em>) he heard my voice.' The word <em>ṣār</em> (distress, narrow place) connects back to the 'narrow straits' imagery of the preceding verses — distress as constriction. 'His temple' (<em>hêḵāl</em>) presents a temporal puzzle: Solomon's temple is not yet built. The term here refers either to the heavenly temple (YHWH's cosmic palace) or to the tabernacle at Nob/Gibeah. The Psalms use <em>hêḵāl</em> for the heavenly dwelling from which YHWH hears prayer (Ps 11:4: 'The LORD is in his holy temple; YHWH, his throne is in heaven'). The cry that enters YHWH's ears is the same <em>šawaʿ</em> (cry for help) used in the Exodus narrative (Exod 2:23).</p>",
    "8": "<p><strong>Theophany: earthquake.</strong> 'The earth reeled (<em>tigʿaš</em>) and shook (<em>wayyirʿaš</em>); the foundations of the heavens (<em>môsədôt haššāmayim</em>) trembled and quaked, because he was angry (<em>ḥārāh lô</em>).' This is the earthquake-theophany tradition that underlies Sinai (Exod 19:18), Ps 68:8, and the eschatological texts of Isa 13:13 and Rev 6:12. The 'foundations of the heavens' reflects an ANE cosmology in which the sky rests on pillars; the phrase appears only here and Ps 18:7. The cause of the cosmic disturbance is explicitly divine anger (<em>ḥārāh</em>), not an impersonal force — YHWH's response to his anointed's distress is personal and cosmic.</p>",
    "9": "<p><strong>Smoke and fire from YHWH's nostrils.</strong> 'Smoke went up from his nostrils (<em>bəʾappô</em>); devouring fire from his mouth.' The Hebrew <em>ʾap</em> means both 'nose/nostril' and 'anger' — the physiological metaphor of anger as smoke from the nostrils. The fire-and-smoke combination draws on Sinai imagery (Exod 19:18, the mountain smoking like a furnace) and the burning bush. 'Blazing coals were kindled by it' (<em>gəḥālîm bāʿărû mimmennû</em>) — the coals that appear before YHWH's chariot-throne (Ezek 1:13; 10:2). The theophany moves from earthquake (v8) to fire (v9) to descent (v10), following the classic Sinai sequence.</p>",
    "10": "<p><strong>Divine descent through the heavens.</strong> 'He parted the heavens (<em>wayyēṭ šāmayim</em>) and came down.' The verb <em>nāṭāh</em> (to stretch, spread, incline) is used of stretching out the heavens in creation contexts (Ps 104:2; Isa 40:22); here it is inverted — YHWH bends/parts the heavens to come down. This is the language of urgent divine intervention, the same vocabulary that Isa 64:1 uses in prayer: 'Oh that you would tear open the heavens and come down!' Dark storm clouds (<em>ʿărāpel</em>, deep darkness/thick gloom) under his feet — the storm-theophany tradition in which YHWH rides the storm.</p>",
    "11": "<p><strong>The cherub-chariot.</strong> 'He rode on a cherub (<em>kərûḇ</em>) and flew; he appeared on the wings of the wind.' The cherub as YHWH's divine chariot/mount is the theology behind the ark (where YHWH sits enthroned above the cherubim, 1 Sam 4:4) and Ezekiel's chariot-throne (<em>merkāḇāh</em>, Ezek 1:4-28). 'Wings of the wind' (<em>kanpê rûaḥ</em>) — the wind as YHWH's vehicle (Ps 104:3: 'who makes the clouds his chariot, who rides on the wings of the wind'). The parallel between the ark-cherubim and this flying-cherub passage suggests that the ark theology of YHWH's mobile throne informs the poetry.</p>",
    "12": "<p><strong>Darkness as canopy.</strong> 'He made darkness (<em>ḥōšeḵ</em>) his canopy (<em>sukkôt</em>) around him — a gathering of waters (<em>ḥaśrat mayim</em>), thick storm clouds (<em>ʿābê šəḥāqîm</em>).' The 'canopy of darkness' is the inverse of the cloud-and-fire pillar that screened YHWH from Israel in the wilderness — the same divine presence that reveals itself in light can also manifest in impenetrable darkness. <em>Sukkôt</em> (booths) is the same word as the festival of booths; the irony of YHWH's dwelling being a booth of darkness is intentional. In Ps 18:11 the variant reads <em>sĕtārô</em> (his hiding place) rather than <em>sukkôt</em>.</p>",
    "13": "<p><strong>Pre-theophanic brightness.</strong> 'Out of the brightness (<em>nōgah</em>) before him' — <em>nōgah</em> is the pre-dawn glow, the halo of divine glory that precedes the full theophanic disclosure (Ezek 1:4, 27-28 uses <em>nōgah</em> for the luminous envelope of the chariot-throne). 'Coals of fire (<em>gaḥălê ʾēš</em>) blazed forth' — the same burning coals before YHWH's throne. The contrast between the surrounding darkness (v12) and the internal brightness (v13) replicates the paradox of the divine glory: hidden and brilliant simultaneously.</p>",
    "14": "<p><strong>Thunder as YHWH's voice.</strong> 'The LORD thundered (<em>yārʿēm</em>) from heaven; the Most High (<em>ʿelyôn</em>) raised his voice.' The thunder = voice of YHWH tradition is developed extensively in Ps 29 ('The voice of the LORD is over the waters; the God of glory thunders, the LORD thunders over the mighty waters,' Ps 29:3). <em>ʿElyôn</em> (Most High) is the ancient El-title that the patriarchs used for the high god (Gen 14:18-22); its pairing with YHWH here as a divine title (as in Ps 7:17; 91:1) expresses YHWH's sovereignty over all divine beings.</p>",
    "15": "<p><strong>Arrows and lightning bolts as weapons.</strong> 'He shot his arrows (<em>ḥiṣṣāyw</em>) and scattered them; lightning bolts (<em>bārāq</em>) and threw them into disorder.' The divine warrior's weapons are the storm's natural forces — lightning as divine arrows is a common ANE motif (Ps 7:13; 18:14; 77:17; 144:6). <em>Bārāq</em> (lightning) appears here as a noun parallel to arrows; in the Ugaritic texts, Baal's weapons are described similarly. The divine warrior scatters (<em>pûṣ</em>) and throws into confusion (<em>hāmam</em>) the enemies — the same verb used of the confusion YHWH causes among enemy armies in the holy-war tradition (Exod 14:24; Josh 10:10).</p>",
    "16": "<p><strong>Channels of the sea exposed.</strong> 'Then the channels (<em>ʾăpîqê</em>) of the sea were exposed (<em>yiggāllû</em>) and the foundations of the world (<em>môsədôt tēḇēl</em>) laid bare, at the LORD's rebuke (<em>gĕʿārāh</em>), at the blast (<em>niššemat</em>) of the breath of his nostrils.' The cosmic scope of YHWH's response to David's cry escalates to include the sea-bed and the world's foundations. <em>Gĕʿārāh</em> (rebuke) is YHWH's sovereign command that restrains the sea (Ps 104:7: 'at your rebuke the waters fled'). <em>Niššāmāh</em> (breath/blast) recalls Gen 2:7 (the breath that animated humanity) — the same divine breath that gives life also unleashes storm and sea.</p>",
    "17": "<p><strong>Rescue from many waters.</strong> 'He reached down from on high and took me (<em>wayyiqqāḥēnî</em>); he drew me out of many waters (<em>mayyim rabbîm</em>).' <em>Mayyim rabbîm</em> (many/mighty waters) is the OT's standard idiom for the cosmic chaos-sea and for overwhelming mortal danger (cf. Song 8:7: 'Many waters cannot quench love'). 'Drew me out' (<em>māšāh</em>) is the same root used for Moses's name in Exod 2:10: 'She drew him out of the water (<em>mĕšîtihû min hammayim</em>).' The rescue of the anointed from many waters echoes the Moses-rescue; the one drawn from water becomes the deliverer of YHWH's people.</p>",
    "18": "<p><strong>Rescue from the powerful enemy.</strong> 'He rescued me from my powerful enemy (<em>ʾōyĕbî ʿāz</em>), from those who hated me (<em>mĕśanʾay</em>) — for they were stronger than I (<em>kî ʾāmĕṣû mimmennî</em>).' The frank admission 'they were stronger than I' is remarkable — the psalm does not pretend David was capable of defeating his enemies; rescue was possible only because YHWH intervened. This is the logic of grace: the rescue is proportioned to the powerlessness of the one rescued. The MT 2 Sam 22 and Ps 18 agree here, underlining that the theological point is not a variant but a settled conviction.</p>",
    "19": "<p><strong>Day of disaster and divine support.</strong> 'They confronted me in the day of my disaster (<em>yôm ʾêdî</em>)' — <em>ʾêd</em> (calamity, destruction) appears in Job as the ultimate reversal of fortune (Job 21:30: 'the wicked is reserved for the day of calamity'). 'But the LORD was my support (<em>miśʿān</em>)' — the same root as the 'staffs' of Isa 3:1 (YHWH removing 'every support'). When all human support structures are removed, YHWH himself becomes the support — the positive side of the judgment that strips away false dependences.</p>",
    "20": "<p><strong>Spacious place and divine delight.</strong> 'He brought me out into a spacious place (<em>merhāḇ</em>); he rescued me (<em>wayyĕḥallĕṣēnî</em>), because he delighted in me (<em>kî ḥāpēṣ bî</em>).' <em>Merhāḇ</em> (open/broad space) contrasts with <em>ṣār</em> (narrow distress) of v7 — the rescue brings David from constriction into expansion. 'He delighted in me' (<em>ḥāpēṣ bî</em>) is the theological crux of the whole poem: the ground of rescue is not David's merit but YHWH's covenantal pleasure in his chosen one. Isaiah 42:1 uses the same formula for the Servant: 'my chosen, in whom my soul delights (<em>rāṣĕtāh napšî</em>).'</p>",
    "21": "<p><strong>Righteousness and cleanness.</strong> 'The LORD rewarded me according to my righteousness (<em>ṣidqātî</em>); according to the cleanness of my hands (<em>bōr yādāy</em>) he repaid me.' The claim of righteousness in vv21-25 has troubled interpreters given David's well-known failures; the most likely reading is that this is the speaker's covenantal integrity — his overall orientation of trust in and loyalty to YHWH — rather than sinless perfection. <em>Bōr</em> (cleanness, purity) appears three times in this section (vv21, 25, and Ps 18:20,24,26) and connotes freedom from defilement rather than absolute sinlessness.</p>",
    "22": "<p><strong>Ways of YHWH kept.</strong> 'For I have kept the ways of the LORD (<em>šāmarttî darḵê YHWH</em>) and have not turned wickedly (<em>lōʾ rāšaʿtî</em>) from my God.' The idiom 'keeping the ways of YHWH' is the Deuteronomic language of covenantal obedience (Deut 5:33; 8:6; 10:12); 'turned wickedly' (<em>rāšaʿ</em>, the verb from <em>rešaʿ</em>, wickedness) means to act in the manner of the wicked, to abandon covenant norms. The self-attestation is the language of covenant integrity, not moral perfectionism.</p>",
    "23": "<p><strong>Ordinances and statutes.</strong> 'For all his ordinances (<em>mišpāṭāyw</em>) were before me, and I did not turn away (<em>sûr</em>) from his statutes (<em>ḥuqqōtāyw</em>).' The pair <em>mišpāṭîm</em> / <em>ḥuqqôt</em> (ordinances / statutes) is the standard Deuteronomic legal vocabulary (Deut 4:1, 5, 8, 14, etc.). 'Before me' (<em>lənegdî</em>) — the ordinances are kept in view, always present as a guide; this is the attitude of Ps 1 ('his delight is in the law of the LORD, and on his law he meditates day and night'). The protestation of vv21-24 is the OT's positive answer to Job's self-defense speeches.</p>",
    "24": "<p><strong>Blameless before him.</strong> 'I was blameless (<em>tāmîm</em>) before him and kept myself from wrongdoing (<em>wayyeʾešmĕr mēʿăwōnî</em>).' <em>Tāmîm</em> (complete, whole, blameless) is the same word used of Noah (Gen 6:9), of Job (Job 1:1: 'blameless and upright'), and of the Passover lamb (Exod 12:5). It denotes wholeness of commitment, not sinless perfection. 'Kept myself from wrongdoing' (<em>ʿāwōn</em>, iniquity) — the reflexive guard against moral failure; the same phrase appears in Ps 18:23 without significant variant.</p>",
    "25": "<p><strong>Repaid according to cleanness.</strong> 'So the LORD has repaid me according to my righteousness, according to my cleanness (<em>bōrî</em>) in his sight (<em>lənegēd ʿênāyw</em>).' The phrase 'in his sight' (<em>lənegēd ʿênāyw</em>) — before his eyes — emphasizes that YHWH's assessment of David's integrity is the standard that matters. Human evaluation is irrelevant; the divine eye that saw Saul's failure also sees David's fidelity. The repetition of the righteousness/cleanness vocabulary from v21 forms an inclusio around the protestation strophe (vv21-25), signaling its completeness as a rhetorical unit.</p>",
    "26": "<p><strong>The correspondence principle.</strong> 'To the faithful (<em>ḥāsîd</em>) you show yourself faithful (<em>titḥassad</em>); to the blameless (<em>tāmîm</em>) you show yourself blameless (<em>titammam</em>).' The <em>hithpael</em> stem of <em>ḥāsad</em> and <em>tāmam</em> is reflexive/middle — YHWH shows himself to be what his partner is; the divine response corresponds to the human posture. This is not merit theology but a description of how covenant relationship works: YHWH meets fidelity with fidelity, purity with purity. The corresponding negative in v27 applies the same logic to the crooked: YHWH meets deviousness with shrewdness.</p>",
    "27": "<p><strong>With the devious, shrewd.</strong> 'To the pure (<em>nāḇār</em>) you show yourself pure; but with the devious (<em>ʿiqqēš</em>) you show yourself shrewd (<em>titpattāl</em>).' The <em>hithpael</em> of <em>pātal</em> (to twist, wrestle) means to show oneself wrestling/twisting — responding to the twisted with a matching complexity. This is not moral equivalence but judicial symmetry: YHWH undoes the plots of the devious by meeting them on their own terrain, using their deviousness against them (as in the Exodus, where Pharaoh's hardness is met with judicial hardening). Ps 18:26 has the same verse with the same vocabulary.</p>",
    "28": "<p><strong>Humble and proud.</strong> 'You deliver a humble people (<em>ʿam ʿānî</em>); but your eyes are on the proud (<em>rāmîm</em>) to bring them low (<em>lĕhašpîlam</em>).' <em>ʿAnî</em> (humble, poor, afflicted) is the same term used of the Servant in Isa 53:4 ('our griefs he bore') and of the messianic king in Zech 9:9 ('your king comes to you, righteous and having salvation, humble and riding on a donkey'). The pairing of humble-deliverance and proud-humiliation is the structural law of divine governance that the NT Magnificat expresses (Luke 1:51-52).</p>",
    "29": "<p><strong>YHWH as lamp.</strong> 'For you are my lamp (<em>nêrî</em>), O LORD, and the LORD lights up my darkness (<em>yasgîr ḥāšĕḵî</em>).' <em>Nêr</em> (lamp) in the Davidic context resonates with the 'lamp for David' formula used in the succession narratives (1 Kgs 11:36; 15:4; 2 Kgs 8:19) — the Davidic line as a lamp that must not be extinguished. Here the metaphor is inverted: it is YHWH who is the lamp for David, not the other way around. Ps 18:28 has an important variant: 'you light my lamp' (<em>taʿîr nêrî</em>) rather than 'you are my lamp.' The 2 Sam 22 version is the bolder claim — YHWH himself is the light, not merely the lighter.</p>",
    "30": "<p><strong>Charging a troop and leaping over a wall.</strong> 'By your help I can charge a troop (<em>bəḵā ārûṣ gədûd</em>); by my God (<em>bēʾlōhay</em>) I can leap over a wall (<em>ʾădallēg šûr</em>).' The pair of military feats — charging troops and leaping walls — functions as a merism for military impossibility: what no human soldier can do, YHWH makes possible. <em>Gădûd</em> (raiding band, troop) and <em>šûr</em> (wall) are both military terms; the combination may reflect specific battles. 'By your help' (<em>bəḵā</em>): the preposition of instrumentality — the source of ability is exclusively divine.</p>",
    "31": "<p><strong>Perfect way and flawless word.</strong> 'As for God, his way (<em>darkô</em>) is perfect (<em>tāmîm</em>); the word of the LORD (<em>ʾimrat YHWH</em>) is flawless (<em>ṣərûpāh</em>). He is a shield (<em>māgēn</em>) for all who take refuge (<em>ḥōsîm</em>) in him.' <em>Ṣārûp</em> (tested, refined) is the metallurgical term for precious metal that has been purified of dross in a smelter (Ps 12:6; 119:140; Prov 30:5). The 'word of YHWH' is proven, tested, and reliable — the same reliability demonstrated in the deliverance the poem celebrates. 'Take refuge' (<em>ḥāsāh</em>) is the covenantal shelter-in-YHWH vocabulary (Ps 2:12; 34:22).</p>",
    "32": "<p><strong>Incomparability formula.</strong> 'For who is God (<em>ʾēl</em>) except the LORD? And who is a rock (<em>ṣûr</em>) besides our God?' The incomparability question (<em>mî ʾēl</em>, who is God?) is the liturgical form of monotheistic confession used in the Exodus traditions (Exod 15:11: 'Who is like you, O LORD, among the gods?') and Deutero-Isaiah (Isa 44:6-8). The double rhetorical question excludes all competitors: no other deity qualifies as <em>ʾēl</em> (God) or <em>ṣûr</em> (rock). The pairing of 'LORD' and 'our God' in v32 (as in v33 'God' and in v48 'God') reflects the synonymous use of the divine names in the poem.</p>",
    "33": "<p><strong>Strong refuge and blameless way.</strong> 'God (<em>hāʾēl</em>) is my strong refuge (<em>maʿûzzî ḥāyil</em>) and has made my way (<em>darḵî</em>) blameless (<em>tāmîm</em>).' The same <em>tāmîm</em> (blameless) used of David's behavior in vv24-25 is here applied to what YHWH has done to David's path — he has made it straight and complete. This is the theology of Ps 37:23: 'The steps of a man are established by the LORD, when he delights in his way.' The 'strong refuge' (<em>maʿûz ḥāyil</em>) combines the protection-vocabulary with the strength/ability vocabulary: YHWH provides both shelter and power.</p>",
    "34": "<p><strong>Hinds' feet.</strong> 'He made my feet like the feet of a deer (<em>ʾayyālôt</em>) and set me secure (<em>wayyaʿămidēnî</em>) on the heights (<em>bāmôtāy</em>).' The deer (specifically the female deer, <em>ʾayyālāh</em>) is celebrated for its sure-footedness on mountain terrain; this is the imagery of Hab 3:19 ('He makes my feet like the feet of a deer; he enables me to tread on the heights'). 'The heights' (<em>bāmôt</em>) is used both for the high places of worship and for military high ground — the verse may carry both meanings: victory over elevated enemies and access to YHWH's presence.</p>",
    "35": "<p><strong>Arms trained for battle.</strong> 'He trains my hands (<em>yĕlammēd yādāy</em>) for battle so that my arms can draw a bow of bronze (<em>qešet nĕḥûšāh</em>).' A 'bow of bronze' is otherwise unattested as a real weapon (bows were wood and sinew); the phrase likely means an exceptionally powerful bow requiring supernatural strength to draw, or uses bronze as a poetic intensifier for hardness. The divine training of human hands for battle connects to Ps 144:1: 'Blessed be YHWH my rock, who trains my hands for war, my fingers for battle.'</p>",
    "36": "<p><strong>Shield of salvation and condescension.</strong> 'You have given me the shield (<em>māgēn</em>) of your salvation (<em>yišʿeka</em>), and your condescension (<em>ʿanwātəḵā</em>) has made me great.' The word <em>ʿanwāh</em> (or <em>ʿanāwāh</em>) rendered 'condescension' is the crux of the verse. The root is debated: most derive it from <em>ʿānāh</em> (to be humble/afflicted), yielding 'humility' — meaning YHWH's willingness to stoop down to human need. Some derive it from <em>ʿānāh</em> (to answer/respond), yielding 'your answer' or 'your responding to me.' Ps 18:35 reads <em>ʿanwāthəḵā</em> in the same form. The MKT's 'condescension' captures the theological point: what has made David great is YHWH's willingness to bend down (<em>šāḥāh</em>) toward one who is small.</p>",
    "37": "<p><strong>Stable footing.</strong> 'You gave a wide path (<em>ṣaʿădî</em>) for my feet so that my ankles (<em>qarsullāy</em>) did not give way (<em>mā'ādû</em>).' <em>Ṣāʿad</em> (step, gait) is the measured stride — YHWH enlarges David's stride so he does not stumble. <em>Qarsōl</em> (ankle) is a rare word appearing only here and Ps 18:36. 'Give way/slip' (<em>māʿad</em>) is the vocabulary of unstable footing on difficult terrain; the military context is footing during battle. The divine provision extends to the most mundane physical detail of David's safety.</p>",
    "38": "<p><strong>Pursuing enemies to their destruction.</strong> 'I pursued (<em>ʾerdōp</em>) my enemies and destroyed them (<em>ʾaššāmiḏēm</em>); I did not turn back until I had consumed them.' The pursuit-to-destruction sequence is the pattern of holy-war total victory (Deut 28:7: 'The LORD will cause your enemies who rise against you to be defeated before you; they shall come out against you one way and flee before you seven ways'). 'Did not turn back' (<em>lōʾ šāḇōtî</em>) expresses unrelenting pursuit — the warrior does not retreat or hesitate.</p>",
    "39": "<p><strong>Rising up and falling beneath.</strong> 'I consumed them; I struck them through so that they could not rise (<em>lōʾ yāqûmû</em>); they fell beneath my feet.' The 'cannot rise' motif appears in Amos 5:2 ('fallen is virgin Israel; she shall rise no more') as the image of irreversible defeat. 'Beneath my feet' (<em>taḥat raglāy</em>) is the subordination/subjugation formula that Ps 110:1 extends to all enemies: 'Sit at my right hand, until I make your enemies your footstool (<em>hadōm rəglêḵā</em>).'</p>",
    "40": "<p><strong>Armed with strength for battle.</strong> 'For you armed me (<em>wattazrēnî</em>) with strength for battle (<em>ḥayil lammilḥāmāh</em>); you made those who rose against me bow down (<em>takrîaʿ</em>) under me.' <em>Āzar</em> (to gird, arm) is the belt/girding vocabulary — YHWH girds David with battle-strength as one arms a soldier. 'Those who rose against me bow down' (<em>takkrîaʿ taḥtāy</em>) uses the prostration verb <em>kāraʿ</em> that appears in the Philippians 2:10 LXX citation: 'at the name of Jesus every knee should bow.'</p>",
    "41": "<p><strong>Enemies turned and fled.</strong> 'You made my enemies turn and flee (<em>nātatāh lî ʿōrep ʾōyĕbāy</em>)' — literally 'you have given me the neck of my enemies' — the image of seeing the enemy's back as they flee. Giving someone's neck/back is the idiom for causing rout (Exod 23:27: 'I will make all your enemies turn their backs to you'). 'I destroyed those who hated me' — <em>mĕśanʾay</em> (those hating me) is the same term used in the covenantal context of 'hating YHWH' (Deut 7:10), applied here to David's enemies as YHWH's enemies.</p>",
    "42": "<p><strong>No savior when they cried.</strong> 'They looked for help, but there was no one to save (<em>lōʾ môšîaʿ</em>); they cried to the LORD, but he did not answer them.' The divine non-response to the enemy's cry in crisis is the inverse of v7, where YHWH heard David's cry. The enemies who cry to YHWH in defeat receive no answer — not because YHWH is inactive, but because they cry from desperation rather than covenant relationship. This is the logic of Prov 1:28-29 (wisdom ignores those who cried out too late) and Matt 7:23 ('I never knew you').</p>",
    "43": "<p><strong>Ground like dust.</strong> 'I ground them fine (<em>ʾeššāḥāqēm</em>) as dust (<em>kʿăpar</em>) before the wind; I crushed and stamped them down like the mire in the streets.' <em>Šāḥaq</em> (to grind fine) describes the pulverizing of something into powder — the same verb used for grinding the golden calf in Exod 32:20. 'Mire of the streets' (<em>kəṭîṭ ḥûṣôt</em>) is the image of mud trampled by foot traffic — the most abased position. The escalation from the previous verses (who cannot rise, v39; bow under me, v40; gave me their backs, v41) reaches its rhetorical climax in pulverization and trampling.</p>",
    "44": "<p><strong>Head of nations.</strong> 'You delivered me from the quarrels (<em>rîḇê</em>) of my people; you kept me as the head of nations (<em>rōʾš gôyim</em>); a people I had not known (<em>lōʾ yādaʿtî</em>) served me.' 'Quarrels of my people' likely refers to internal Israelite political opposition — the Saul loyalists, the Benjaminite resistance, and Absalom's revolt. 'Head of nations' (<em>rōʾš gôyim</em>) points to the fulfillment of the Abrahamic promise through David; those who 'had not known' him — foreign nations — come under his authority, fulfilling Ps 2:8: 'I will make the nations your heritage.'</p>",
    "45": "<p><strong>Foreigners submit.</strong> 'Foreigners (<em>bənê nēḵār</em>) came cringing (<em>yikkāḥăšû</em>) to me; as soon as they heard of me they obeyed me.' <em>Bənê nēḵār</em> (sons of the foreign/alien) is the term for non-Israelites used in Isa 56:3-7 to describe those who will join themselves to YHWH in the eschatological community. <em>Kāḥaš</em> (to submit feigning, to cringe, to feign obedience) can have a negative connotation of reluctant/pretended submission (Ps 66:3; 81:15); the nations submit to David but their obedience may not be wholehearted — yet they serve nonetheless.</p>",
    "46": "<p><strong>Foreigners lose heart.</strong> 'Foreigners lost heart (<em>yibbolû</em>) and came trembling (<em>wayyaḥgərû</em>) from their strongholds.' <em>Nāḇal</em> (to wither, fade, lose heart) is the same verb used for withering leaves (Isa 1:30; 40:7-8); applied to the enemy it suggests the collapse of their vitality and resolve. 'Trembling from their strongholds' (<em>misgĕrôtêhem</em>): the fortified places they retreated to become traps rather than refuges. Ps 18:45 has the same verse but with a variant <em>yaḥgərû</em> reading that the MKT follows.</p>",
    "47": "<p><strong>Doxological climax.</strong> 'The LORD lives (<em>ḥay YHWH</em>)! Blessed be my Rock (<em>bārûḵ ṣûrî</em>)! Exalted (<em>yārōm</em>) be my God, the Rock of my salvation (<em>ṣûr yišʿî</em>)!' The <em>ḥay YHWH</em> (the LORD lives/as the LORD lives) formula is the primary oath formula in the OT (Ruth 3:13; 1 Sam 14:39; 2 Sam 4:9) — used in legal oaths and here in doxological proclamation. Its use celebrates YHWH's living, active, victorious reality over against the dead idols (Jer 10:10: 'But the LORD is the true God; he is the living God'). The <em>ṣûr</em> (rock) of salvation forms a closing bracket with the same word in vv2-3.</p>",
    "48": "<p><strong>God of vengeance and victory over peoples.</strong> 'The God (<em>hāʾēl</em>) who gives me vengeance (<em>nōtēn nĕqāmôt</em>) and brings down peoples (<em>môrîd ʿammîm</em>) under me.' <em>Nāqam</em> (vengeance, vindication) is YHWH's prerogative and function as divine judge (Deut 32:35: 'Vengeance is mine, and recompense'; Rom 12:19 cites this). The vengeance is not David's personal revenge but YHWH's judicial action on behalf of his anointed — the vindication of the righteous that the poem has argued for. 'Brings down peoples' (<em>môrîd ʿammîm</em>) connects to the humbling of the proud in v28.</p>",
    "49": "<p><strong>Rescued from the violent man.</strong> 'Who brought me out (<em>môṣîʾî</em>) from my enemies. You exalted me (<em>tĕrômĕmēnî</em>) above those who rose against me; you rescued me from the violent man (<em>ʾîš ḥāmāsîm</em>).' 'The violent man' (<em>ʾîš ḥāmāsîm</em>, literally 'man of violences') is a type that appears in Ps 18:48 as 'man of violence' (<em>ʾîš ḥāmās</em>). The singular 'violent man' may refer specifically to Saul (the primary enemy of the superscription) or to a representative enemy type. Paul cites the opening of v50 in Rom 15:9 as evidence for the Gentile mission.</p>",
    "50": "<p><strong>Praise among the nations.</strong> 'Therefore I will praise you (<em>ʾôdəḵā</em>), O LORD, among the nations (<em>baggôyim</em>), and sing praises (<em>ʾăzammərah</em>) to your name (<em>šimḵā</em>).' The <em>yôd</em> imperfect <em>ʾôdəḵā</em> is the vow-of-praise formula common in thanksgiving psalms — the psalmist commits himself to public acknowledgment of YHWH's deliverance. Paul cites this verse in Rom 15:9 as the voice of Christ praising the Father among the Gentiles, reading the 'nations' (<em>gôyim</em>) as the Gentile mission. The placing of YHWH's praise among the nations is not a new impulse but the fulfillment of the Davidic covenant's worldwide scope.</p>",
    "51": "<p><strong>Steadfast love to the anointed forever.</strong> 'He gives great victories (<em>migdôl yĕšûʿôt</em>) to his king (<em>malkô</em>) and shows steadfast love (<em>ḥesed</em>) to his anointed (<em>mĕšîḥô</em>) — to David and his descendants (<em>wəlzarʿô</em>) forever (<em>ʿad ʿôlām</em>).' The final verse of the poem is the Davidic covenant in miniature: the king (<em>melek</em>) and the anointed (<em>māšîaḥ</em>) are the two titles of the covenant heir; <em>ḥesed</em> (covenant faithfulness) is the binding quality of YHWH's commitment; 'his seed forever' (<em>zarʿô ʿad ʿôlām</em>) is the eternal dynastic promise of 2 Sam 7:13, 16. The poem ends exactly where the Davidic covenant ends: with an eternal promise to the anointed and his seed.</p>"
  },
  "23": {
    "1": "<p><strong>The oracle formula and messianic title-cluster.</strong> 'The declaration (<em>nĕʾum</em>) of David son of Jesse, the declaration of the man God raised to prominence (<em>hāʾîš huqqam ʿal</em>), the anointed (<em>mĕšîaḥ</em>) of the God of Jacob, the beloved singer (<em>nĕʿîm</em>) of Israel's psalms.' <em>Nĕʾum</em> is the prophetic oracle formula — 'utterance/declaration' — used predominantly of divine speech ('declaration of YHWH', <em>nĕʾum YHWH</em>, appears hundreds of times in the prophets). Its application to David marks this as a prophetic oracle. <em>Huqqam ʿal</em> ('raised on high/raised to prominence') — the Hophal of <em>qûm</em> (to rise/establish) — anticipates the resurrection-exaltation language the NT applies to Christ. <em>Nĕʾîm</em> (lovely, pleasant, beloved) shares the root with Naomi (pleasant) and Jonathan's lament ('how lovely (<em>nāʿamtā</em>) were you to me,' 2 Sam 1:26).</p>",
    "2": "<p><strong>Spirit-inspired speech.</strong> 'The Spirit of the LORD (<em>rûaḥ YHWH</em>) speaks (<em>dibber</em>) through me; his word (<em>millātô</em>) is on my tongue (<em>ʿal lĕšônî</em>).' The claim is unambiguous prophetic inspiration: the Spirit of YHWH is the grammatical subject of <em>dibber</em> (spoke, perfect tense — the speaking has already occurred and its effect remains). <em>Millāh</em> (word, utterance) is the Aramaic loan-word that appears in Aramaic sections of Daniel and Job; its use here is unusual in Hebrew narrative, possibly reflecting the archaic poetic register of the oracle. 'On my tongue' — the Spirit-word is not merely in David's mind but on his tongue, as in Isa 51:16 (YHWH puts his words in the Servant's mouth).</p>",
    "3": "<p><strong>The just ruler ideal.</strong> 'The God of Israel has spoken (<em>dĭbbēr ʾĕlōhê yiśrāʾēl</em>); the Rock of Israel (<em>ṣûr yiśrāʾēl</em>) has said to me: Whoever rules over men with justice (<em>môšēl bāʾādām ṣaddîq</em>), who rules in the fear of God (<em>mōšēl yirʾat ʾĕlōhîm</em>).' The verse is grammatically difficult — it functions as a conditional clause whose apodosis follows in v4. <em>Ṣaddîq</em> (just, righteous) applied to the ruler is the ideal of Ps 72: 'Give the king your justice (<em>mišpāṭîm</em>), O God, and your righteousness (<em>ṣidqāh</em>) to the royal son.' The 'fear of God' as the governing principle of the just ruler is the root of all covenant ethics (Prov 1:7: 'the fear of the LORD is the beginning of wisdom').</p>",
    "4": "<p><strong>Light-of-morning simile.</strong> 'He is like the light of morning (<em>kəʾôr bōqer</em>), like sunrise on a cloudless day (<em>šemeš bōqer</em>), like the gleam of rain (<em>minnōgah</em>) on green grass (<em>dešeʾ</em>) after showers.' Three similes describe the effect of the just ruler: morning light (dispelling darkness), sunrise on clear sky (unobstructed brilliance), and rain-gleam on grass (the combination of sun and moisture that makes growth possible). <em>Nōgah</em> (brightness, gleam) is the same word used for the halo around the divine chariot-throne in Ezek 1:4, 27-28. The ideal ruler's effect on the land is like the first light of dawn — he brings life and clarity after the darkness of oppression.</p>",
    "5": "<p><strong>Everlasting covenant.</strong> 'Is it not true that my house stands so before God? For he has made with me an everlasting covenant (<em>bĕrît ʿôlām</em>), ordered (<em>ʿărûḵāh</em>) and secured (<em>šəmûrāh</em>) in every way.' The verse is syntactically difficult: the opening <em>kî lōʾ</em> is either negative ('surely not so is my house with God') or strongly asseverative ('surely thus is my house with God'). The context and the confident declaration that follows suggest the asseverative reading. <em>Bĕrît ʿôlām</em> (everlasting covenant) is the technical term for the unconditional Davidic covenant of 2 Sam 7 (also Isa 55:3; Ps 89:28). 'Ordered and secured' (<em>ʿărûḵāh ûšəmûrāh</em>) — the covenant is organized and guarded, reliable at every point. 'All my salvation and all my desire' — the covenant is the ground of all confident expectation.</p>",
    "6": "<p><strong>Worthless men like thorns.</strong> 'But worthless men (<em>bəliyyaʿal</em>) are like thorns (<em>qôṣ</em>) that are cast away (<em>munādîm</em>), for they cannot be taken up with the hand.' <em>Bĕliyyaʿal</em> (Belial, worthlessness) is the same characterization of Eli's sons (1 Sam 2:12) and Nabal (1 Sam 25:25) — those who operate entirely outside covenant norms. The thorn-imagery for the wicked appears in Ezek 28:24 ('a brier or a thorn' for hostile nations) and Mic 7:4. Thorns that cannot be handled safely are discarded — the worthless have no useful function in the covenant community and are ultimately removed from it.</p>",
    "7": "<p><strong>Iron and fire for the thorns.</strong> 'Whoever touches them must be armed with iron (<em>barzel</em>) and the shaft of a spear (<em>ʿēṣ ḥanît</em>), and they are utterly burned up (<em>śārôp yiśśārĕpû</em>) where they stand.' The handling of thorns requires armored protection — iron and spear-shaft as protection against their snagging. 'Utterly burned' uses the infinitive absolute for emphasis (<em>śārôp yiśśārĕpû</em>, burning they are burned) — the complete and irreversible incineration of the worthless. Judgment on the covenant-breakers is not gradual but total. This verse closes the oracle with a judicial note: the just ruler's reign (vv3-5) means the end of the worthless (vv6-7).</p>",
    "8": "<p><strong>Josheb-basshebeth and the eight hundred / three hundred problem.</strong> 'Josheb-basshebeth the Tahchemonite, chief of the Three. He raised his spear (<em>ḥănîtô</em>) against eight hundred (<em>šĕmōneh mēʾôt</em>) men and killed them in a single battle.' The parallel in 1 Chr 11:11 reads 'three hundred' rather than 'eight hundred' — one of the clearest numerical discrepancies between Samuel and Chronicles. The Chronicler typically reduces numbers (a tendency also seen in census figures); some MSS of LXX have intermediate numbers. The MT of 2 Sam 22 ('eight hundred') is likely the earlier reading. The feat, however numbered, establishes the category of warrior whose single-handed lethality qualifies him for the honor list.</p>",
    "9": "<p><strong>Eleazar at Pas-dammim.</strong> 'Next to him among the three warriors was Eleazar son of Dodo son of Ahohi. He was with David when they taunted (<em>ḥērĕpû</em>) the Philistines gathered for battle at Pas-dammim.' <em>Ḥārap</em> (to taunt, reproach, defy) is the verb used of Goliath's taunting in 1 Sam 17:10, 25, 26, 36 — the defiance that motivates the battle. The connection establishes continuity between David's Goliath victory and his mighty men's later battles: they fight in the same spirit of covenant defiance of YHWH's enemies.</p>",
    "10": "<p><strong>Hand frozen to the sword.</strong> 'He held his ground and struck down Philistines until his hand grew tired and his hand froze to the sword (<em>wattidbaqa yādô ʾel hahereḇ</em>). The LORD brought about a great victory that day.' The graphic detail of the hand seizing to the sword-grip in prolonged combat is one of the most vivid military images in the OT. 'YHWH brought about a great victory' (<em>waYYHWH ʿāśāh tĕšûʿāh gĕdôlāh</em>) — the divine agent is explicitly credited with the outcome, while Eleazar's action is the human instrument. The pattern of human effort completed by divine victory characterizes all the mighty men narratives.</p>",
    "11": "<p><strong>Shammah at the lentil field.</strong> 'Next was Shammah son of Agee the Hararite. The Philistines had gathered at Lehi (<em>Leḥî</em>), where there was a field full of lentils (<em>ʿădāšîm</em>).' Lehi ('jawbone') is the site of Samson's slaughter of the Philistines in Judg 15:9-17 — the same location sanctifies a later Philistine confrontation. Lentils are a common crop in Judah (red lentils = the Esau/Jacob transaction in Gen 25:34; lentils in David's provisions in 2 Sam 17:28). The detail of the crop establishes that this is a battle to defend ordinary agricultural life — the food security of YHWH's people at stake in the military standoff.</p>",
    "12": "<p><strong>Shammah's stand and YHWH's victory.</strong> 'But he planted himself (<em>wayyityaṣṣēb</em>) in the middle of the field, defended it (<em>wayyaṣṣîlehā</em>), and struck down the Philistines. The LORD brought about a great victory.' <em>Yāṣab</em> (hithpael: to position/plant oneself firmly) is the military term for taking a stand — the same root used in 1 Sam 17:16 (Goliath 'stationed himself' every day). The repetition of the YHWH-victory formula (also v10) bookends the three warriors' individual stories and insists that the honor belongs to YHWH: the warriors are instruments of divine deliverance, not autonomous heroes.</p>",
    "13": "<p><strong>The cave of Adullam and Bethlehem.</strong> 'Three of the thirty chief warriors went down at harvest time and came to David at the cave of Adullam (<em>mĕʿārat ʿAdullām</em>), while a Philistine raiding band was encamped in the Valley of Rephaim (<em>ʿēmeq rĕpāʾîm</em>).' The cave of Adullam is David's primary refuge in his fugitive period (1 Sam 22:1-2); its mention here recalls those desperate years and establishes the bond between David and these men as forged in adversity. The Valley of Rephaim (modern Baqa'a, west of Jerusalem) is the battle-site of 2 Sam 5:17-25 — providing a possible geographical connection to the Baal-perazim victory.</p>",
    "14": "<p><strong>David in the stronghold, Philistines at Bethlehem.</strong> 'David was in the stronghold (<em>mĕṣûdāh</em>) at the time, and the Philistine garrison (<em>nĕṣîḇ</em>) was at Bethlehem.' The <em>mĕṣûdāh</em> may be the cave of Adullam or a different refuge; Bethlehem is David's hometown (1 Sam 16:1, 18; 17:58). The Philistine occupation of Bethlehem — the city of David's birth and family — intensifies the emotional resonance of his longing in v15. The garrison (<em>nĕṣîḇ</em>) is a military post, an occupying force maintaining Philistine control over the Judean countryside.</p>",
    "15": "<p><strong>David's longing for water.</strong> 'David was overcome with longing (<em>wayyitʾawweh dawid</em>) and said, &ldquo;O that someone would bring me water to drink from the well at Bethlehem's gate!&rdquo;' The verb <em>ʾāwāh</em> (to long, crave, desire) in the hithpael is intense longing — the same root used in Num 11:4 for the mixed multitude's craving and in Deut 12:20 for legitimate desire. The desire for water from the specific well at Bethlehem's gate is simultaneously a military impossibility (behind enemy lines) and an intensely personal, nostalgic yearning — the longing of a man separated from his homeland by war.</p>",
    "16": "<p><strong>The water poured out to YHWH.</strong> 'Then the three warriors broke through (<em>wayyibbĕqĕʿû</em>) the Philistine lines, drew water from the well at Bethlehem's gate, and carried it back to David. But he refused (<em>wayyĕmaʾēn</em>) to drink it. He poured it out (<em>wayassĕḵēhû</em>) to the LORD.' David's refusal and libation is one of the most theologically profound acts in the narrative. The pouring out of water as a libation (<em>nāsaḵ</em>) to YHWH is a sacrificial act (1 Sam 7:6); the libation acknowledges that what was obtained at the risk of life is sacred — too precious for personal use and belonging to YHWH. The blood-equivalent status of the water (explicitly stated in v17) makes the libation a kind of non-blood atonement.</p>",
    "17": "<p><strong>Blood of the men.</strong> 'And said, &ldquo;Far be it from me, O LORD, to do this! Is this not the blood (<em>dām</em>) of the men who went at the risk of their own lives (<em>bĕnapšôtām</em>)?&rdquo; So he would not drink it.' David explicitly calls the water 'the blood of the men' — the equation of water obtained at mortal risk with the men's own lifeblood. <em>Bĕnapšôtām</em> (with their lives/souls) identifies the water as the men's <em>nepheš</em> (life-force) itself — if blood is the seat of life (Lev 17:11), then water won at mortal peril is functionally equivalent to blood. David's refusal to consume it and his libation-to-YHWH is an act of theological precision: he will not consume what belongs to YHWH as the Lord of life.</p>",
    "18": "<p><strong>Abishai and his naming alongside the Three.</strong> 'Abishai, the brother of Joab son of Zeruiah, was head of the Thirty (<em>rōʾš haššəlōšāh</em>).' A text-critical issue: MT reads 'the Three' (<em>haššəlōšāh</em>) rather than 'the Thirty' (<em>haššəlōšîm</em>); LXX supports 'the Thirty.' The distinction matters: Abishai is either chief of the inner Three (the elite) or head of the broader Thirty. The following verse specifies he 'did not attain to the Three,' which would be contradictory if he were 'head of the Three.' The MKT follows the Thirty reading as more consistent. 'He raised his spear against three hundred men, killed them, and earned a name (<em>wayyiqrāʾ šĕmô</em>) alongside the Three.'</p>",
    "19": "<p><strong>Abishai's honor without membership.</strong> 'He was the most honored of the Thirty (<em>nikkbāḏ miššəlōšîm</em>) and became their commander, but he did not attain to the Three (<em>wĕʾel haššəlōšāh lōʾ bāʾ</em>).' The formal hierarchy is: the Three (elite inner circle) > the Thirty (broader honor guard) > the general army. Abishai occupies the highest position within the Thirty but cannot reach the Three's level. The honest recording of who attained the highest honors and who did not — without embarrassment about the gradations — reflects the honor-culture of the ancient warrior society.</p>",
    "20": "<p><strong>Benaiah's exploits.</strong> 'Benaiah son of Jehoiada was a valiant warrior (<em>ben ʾîš ḥayil</em>) from Kabzeel, a man of great deeds (<em>rab pĕʿālîm</em>). He struck down two warriors of Moab (<em>ʾărîʾēl môʾāb</em>). He also went down and killed a lion in a pit on a day when snow had fallen.' <em>ʾĂrîʾēl</em> (probably 'hero of God' or 'lion of God') is a rare word used also as a name for Jerusalem (Isa 29:1-2). The lion-in-pit-in-snow exploit is remarkable for its specificity of circumstance: the snow made the terrain treacherous, the pit confined the lion — the odds were maximized against Benaiah, and he prevailed anyway.</p>",
    "21": "<p><strong>The Egyptian's spear.</strong> 'He also struck down a formidable Egyptian (<em>ʾîš miṣrî mar'eh</em>). The Egyptian had a spear (<em>ḥanît</em>) in his hand, but Benaiah went against him with a club (<em>šēḇeṭ</em>), snatched the spear from his hand, and killed him with his own spear.' The reverse-weapon motif — taking the enemy's weapon and killing him with it — recalls David and Goliath's sword (1 Sam 17:51). The irony of the superior weapon turned against its owner is a recurring literary trope expressing divine reversal: the powerful are undone by their own instruments. Benaiah's club vs. the Egyptian's spear is a deliberate underdog scenario.</p>",
    "22": "<p><strong>Benaiah's name alongside the Three.</strong> 'These were the things Benaiah son of Jehoiada did, and he won a name alongside the three warriors.' The name-winning (<em>šēm</em>) formula is the ancient honor culture's acknowledgment: a man's deeds earn him a permanent reputation (<em>šēm</em>). The same <em>šēm</em>-formula appears in Gen 6:4 for the Nephilim ('men of renown, the men of name') — indicating that the category of famous warrior is archaic. That Benaiah wins a name 'alongside the Three' without being one of them is another precise gradation of honor.</p>",
    "23": "<p><strong>Benaiah over the bodyguard.</strong> 'He was more honored than the Thirty, but he did not attain to the Three. David placed him in charge of his bodyguard (<em>mišmaʿ</em>).' Benaiah's subsequent career confirms his elite status: he executes Joab (1 Kgs 2:34) and Shimei (1 Kgs 2:46) for Solomon and is appointed commander of the army in Joab's place (1 Kgs 2:35) — the highest military office in Israel. His placement over the <em>mišmaʿ</em> (the royal guard, literally 'listening/compliance force') is the first step in a career that will define Solomon's reign.</p>",
    "24": "<p><strong>Opening of the Thirty list.</strong> 'Asahel the brother of Joab was one of the Thirty; Elhanan son of Dodo of Bethlehem.' The list includes Asahel, killed by Abner in 2 Sam 2:23 — his presence in the Thirty means the list preserves names of men who served in David's early career, including those who died in the civil war period. Elhanan of Bethlehem is noteworthy: the 'Elhanan who killed Goliath' tradition (2 Sam 21:19; 1 Chr 20:5 corrects to 'Lahmi, brother of Goliath') may reflect the same individual or a different Elhanan from the same city.</p>",
    "25": "<p><strong>Shammah and Elika of Harod.</strong> 'Shammah of Harod, Elika of Harod.' Harod is the spring where Gideon's army was tested (Judg 7:1 — 'the spring of Harod'), which flows at the northern foot of Mount Gilboa. The region of Harod/Gilboa is militarily significant as the site of both Gideon's victory and Saul's defeat (1 Sam 31). Men from this region in David's honor guard represent the incorporation of Saul's former territory into the Davidic military structure.</p>",
    "26": "<p><strong>Helez and Ira.</strong> 'Helez the Paltite, Ira son of Ikkesh of Tekoa.' Tekoa is Amos's hometown (Amos 1:1) and the city from which Joab recruits the wise woman in 2 Sam 14:2. Ira the Tekoite thus comes from a region associated with wisdom and prophecy. 'Ira son of Ikkesh of Tekoa' appears in the monthly rotation of 1 Chr 27:9 as commander of the ninth monthly division — his Thirty membership is confirmed in the administrative lists.</p>",
    "27": "<p><strong>Abiezer and Mebunnai.</strong> 'Abiezer of Anathoth, Mebunnai the Hushathite.' Anathoth is the priestly city in Benjamin, later the birthplace of Jeremiah (Jer 1:1). An Abiezer of Anathoth in the Thirty suggests the military integration of priestly-tribal territories. 'Mebunnai the Hushathite' is likely the same as Sibbechai the Hushathite (2 Sam 21:18; 1 Chr 11:29: Sibbechai), who slew Saph/Sippai the Philistine — a scribal variant between <em>Mĕḇunnay</em> and <em>Sibḇĕḵay</em>.</p>",
    "28": "<p><strong>Zalmon and Maharai.</strong> 'Zalmon the Ahohite, Maharai of Netophah.' Netophah (modern Khirbet Bedd Faluh, south of Bethlehem) appears in the post-exilic return lists (Ezra 2:22; Neh 7:26) as a significant Judean village. Two Netophathites appear in the Thirty (Maharai, v28, and Heleb, v29), suggesting a concentration of military talent in that village. The 'Ahohite' designation (Zalmon, Eleazar in v9) connects to the clan of Ahoh in Benjamin (1 Chr 8:4).</p>",
    "29": "<p><strong>Heleb and Ittai.</strong> 'Heleb son of Baanah of Netophah, Ittai son of Ribai of Gibeah of Benjamin.' Gibeah of Benjamin is Saul's city (1 Sam 10:26; 11:4) — Ittai son of Ribai from Gibeah in David's Thirty represents the absorption of Saul's tribal homeland into Davidic military service. This is politically significant: Benjamin, the tribe most resistant to David (the Sheba revolt of 2 Sam 20 is led by a Benjaminite), nevertheless contributes men to David's elite guard.</p>",
    "30": "<p><strong>Benaiah and Hiddai.</strong> 'Benaiah of Pirathon, Hiddai of the wadis of Gaash.' Pirathon is in the hill country of Ephraim (Judg 12:15 — home of the judge Abdon). Benaiah of Pirathon (not the same as Benaiah son of Jehoiada, v20) appears in the monthly rotation of 1 Chr 27:14. The 'wadis of Gaash' appear in Josh 24:30 and Judg 2:9 as the burial site of Joshua — a geographical marker connecting David's warriors to the conquest generation's inheritance.</p>",
    "31": "<p><strong>Abi-albon and Azmaveth.</strong> 'Abi-albon the Arbathite, Azmaveth of Bahurim.' Bahurim is the village where Shimei cursed David during the Absalom revolt (2 Sam 16:5) — having an elite warrior from Bahurim in the Thirty suggests that this Benjaminite village had mixed loyalties. Azmaveth of Bahurim is also listed in 1 Chr 11:33 as Azmaveth the Baharumite; his name appears in 2 Sam 23:31 without the variant. Azmaveth is also the name of David's chief treasurer (1 Chr 27:25 — the same individual or a namesake).</p>",
    "32": "<p><strong>Eliahba and Jonathan.</strong> 'Eliahba the Shaalbonite, the sons of Jashen, Jonathan.' 'The sons of Jashen' is a textual problem — 1 Chr 11:34 reads 'the sons of Hashem the Gizonite' and the name Jonathan appears as the son of Shage the Hararite. The MT here gives 'the sons of Jashen (<em>bənê yāšēn</em>), Jonathan' — multiple sons of Jashen plus a Jonathan. The textual confusion likely reflects scribal error (haplography or metathesis) in one of the two traditions.</p>",
    "33": "<p><strong>Shammah the Hararite and Ahiam.</strong> 'Shammah the Hararite, Ahiam son of Sharar the Hararite.' The 'Hararite' gentilic appears three times in the Thirty (Shammah son of Agee in v11, and two in v33) — a clan or geographical designation (possibly 'of the hill/mountain,' from <em>hār</em>). Shammah of Harod (v25) and Shammah the Hararite (v33) are two distinct individuals sharing a common name.</p>",
    "34": "<p><strong>Eliphelet and Eliam.</strong> 'Eliphelet son of Ahasbai of Maacah, Eliam son of Ahithophel the Gilonite.' Eliam son of Ahithophel is the only person in the list identifiable by family connection to a named figure: Ahithophel is David's chief counselor who defected to Absalom (2 Sam 15:12; 16:20-17:23). If Eliam is also the father of Bathsheba (2 Sam 11:3), then Eliam is the son of Ahithophel and father of Bathsheba — which would make Ahithophel Bathsheba's grandfather, and his betrayal of David potentially motivated by revenge for David's treatment of his granddaughter.</p>",
    "35": "<p><strong>Hezro and Paarai.</strong> 'Hezro of Carmel, Paarai the Arbite.' Carmel (near Maon in Judah) is Nabal's estate (1 Sam 25:2) and the site of Abigail's encounter with David — a geographical connection between the Thirty and the David-Abigail narrative. 1 Chr 11:37 reads 'Naarai son of Ezbai' where 2 Sam 23:35 has 'Paarai the Arbite' — another textual variant between the two lists.</p>",
    "36": "<p><strong>Igal and Bani.</strong> 'Igal son of Nathan of Zobah, Bani the Gadite.' 'Son of Nathan of Zobah' — this Nathan is presumably a Zobahite, not the prophet Nathan. Zobah (Aram-Zobah) is the Aramean kingdom David defeated (2 Sam 8:3-8; 10:6-19) — having a Zobahite in the Thirty indicates that Davidic military service incorporated men from conquered territories. Bani the Gadite represents the Transjordanian tribes in the honor roll.</p>",
    "37": "<p><strong>Zelek and Naharai.</strong> 'Zelek the Ammonite, Naharai of Beeroth — the armor-bearer (<em>nōśēʾ kēlîm</em>) of Joab son of Zeruiah.' Zelek the Ammonite is one of two explicitly foreign members of the Thirty (the other being Uriah the Hittite, v39), confirming that David's elite guard included non-Israelites on the basis of personal loyalty and military valor. Naharai of Beeroth as Joab's armor-bearer establishes a personal connection between the Thirty and Joab's command structure — the armor-bearer of the commander is himself an elite warrior.</p>",
    "38": "<p><strong>Ira and Gareb the Ithrites.</strong> 'Ira the Ithrite, Gareb the Ithrite.' The Ithrites are a clan of Kiriath-jearim (1 Chr 2:53). Their presence in the Thirty reflects David's draw on talent from across Judah and Benjamin — including those from the area where the ark rested at Abinadab's house (1 Sam 7:1-2; 2 Sam 6:3-4), suggesting possible cultic connection to the ark-transport tradition.</p>",
    "39": "<p><strong>Uriah the Hittite — the final name.</strong> 'Uriah the Hittite — thirty-seven in all.' Uriah the Hittite is named last in the Thirty, after all other warriors. He is the most faithful of David's mighty men — his insistence on maintaining the military abstinence code while David committed adultery with his wife (2 Sam 11:6-13) is a sustained act of integrity that made his king's guilt all the more glaring. The summary count of thirty-seven matches the list as given. Uriah's position as the final name in the honor roll of the greatest warriors in David's service is the narrator's quiet indictment: David murdered the man whose name the list ends with. Matthew 1:6 will permanently preserve this indictment in the genealogy of Jesus.</p>"
  }
}

def main():
    c = load_comm('mkt-original', '2samuel')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', '2samuel', c)
    total = sum(len(v) for v in ORIGINAL.values())
    print(f'2samuel mkt-original ch22-23: wrote {total} verses')

if __name__ == '__main__':
    main()
